            ),
          ),
        ),
      ],
    );
  }

  Widget _buildLink(
    BuildContext context,
    String label,
    VoidCallback onTap, {
    bool withSeparator = false,
  }) {
    return Row(
      mainAxisSize: MainAxisSize.min,
      children: [
        if (withSeparator) ...[
          Text(
            '|',
            style: Theme.of(context).textTheme.bodySmall?.copyWith(
                  color: Theme.of(context).colorScheme.onSurfaceVariant,
                ),
          ),
          const Gap(2),
        ],
        TextButton(
          onPressed: onTap,
          child: Text(
            label,
            style: Theme.of(context).textTheme.bodySmall?.copyWith(
                  color: Theme.of(context).colorScheme.onSurfaceVariant,
