// Flutter imports:
import 'package:flutter/foundation.dart';

// Package imports:
import 'package:flutter_hooks/flutter_hooks.dart';

Future<void> Function({T? data}) useSingleAction<T>({
  required AsyncValueSetter<T?> asyncCallback,
}) {
  final executing = useRef(false);
  return ({T? data}) async {
    if (executing.value) return;
    executing.value = true;
    try {
      await asyncCallback(data);
    } finally {
      // Ensure the flag is reset even when an error occurs
      executing.value = false;
    }
  };
}

